final:
module top_module(
    input reset,
    input clk,
    input ld,
    input [7:0] acc_in,
    output reg [7:0] acc_out
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge reset or posedge dbg_halt)begin
    if(reset)
        acc_out <= 8'b0000_0000;
    else
        if(ld)
            acc_out <= acc_in;
end
endmodule
